import { cn } from '@/utils/cn';
import { Image } from '@/utils/helper';
import { ImagePreview } from '@components/image-preview';
import { Component, createSignal, Show } from 'solid-js';
import { ImagePreviewProps } from '../image-preview/image-preview';

export const Hover3DImage: Component<{
  image: Image;
  /** Bật/tắt tính năng click để preview ảnh. @default true */
  preview?: boolean | { enabled: true; previewOptions?: ImagePreviewProps };
  class?: Partial<Record<'root' | 'figure' | 'image', string>>;
}> = p => {
  const [open, setOpen] = createSignal(false);
  const previewEnabled = () => p.preview !== false;

  return (
    <>
      <div
        class={cn('hover-3d', previewEnabled() && 'cursor-zoom-in', p.class?.root)}
        onClick={() => previewEnabled() && setOpen(true)}
      >
        <figure class={cn('rounded-2xl', p.class?.figure)}>
          <img {...p.image} />
        </figure>
        <div></div>
        <div></div>
        <div></div>
        <div></div>
        <div></div>
        <div></div>
        <div></div>
        <div></div>
      </div>

      <Show when={open()}>
        <ImagePreview
          src={p.image.src}
          imageName={typeof p.image.alt === 'string' ? p.image.alt : undefined}
          onClose={() => setOpen(false)}
          {...(typeof p.preview === 'object' ? p.preview.previewOptions : undefined)}
        />
      </Show>
    </>
  );
};
